-- Limpar dados existentes (caso haja)
DELETE FROM phaseAlertMargins;

-- Inserir margens por fase
-- MAINTENANCE: condições estáveis para plantas-mãe, tolerância moderada
INSERT INTO phaseAlertMargins (phase, tempMargin, rhMargin, ppfdMargin, phMargin) VALUES
('MAINTENANCE', 2.0, 5.0, 75, 0.3);

-- CLONING: condições mais críticas para enraizamento, tolerância menor
INSERT INTO phaseAlertMargins (phase, tempMargin, rhMargin, ppfdMargin, phMargin) VALUES
('CLONING', 1.5, 4.0, 50, 0.2);

-- VEGA: fase vegetativa, tolerância moderada
INSERT INTO phaseAlertMargins (phase, tempMargin, rhMargin, ppfdMargin, phMargin) VALUES
('VEGA', 2.0, 5.0, 100, 0.3);

-- FLORA: floração, controle mais rigoroso (RH alto favorece botrytis)
INSERT INTO phaseAlertMargins (phase, tempMargin, rhMargin, ppfdMargin, phMargin) VALUES
('FLORA', 1.5, 3.0, 100, 0.2);

-- DRYING: secagem, controle muito rigoroso de RH e temperatura (sem pH)
INSERT INTO phaseAlertMargins (phase, tempMargin, rhMargin, ppfdMargin, phMargin) VALUES
('DRYING', 1.0, 2.0, 0, NULL);

